enter_flag : BOOL;
exit_flag : BOOL;
VehicleNumber_in : INT;
END_VAR
VAR_OUTPUT
truck : T_TRUCK_INFO;
END_VAR
VAR_IN_OUT
garage : ARRAY[1..3, 1..5] OF T_GARAGE_SLOT;
